    public function getSourceContext()
    {
        return new Source("{% extends 'layout.html.twig' %}

{% block page_title %}Restablecer contraseña | {% endblock %}

{% block content %}
    <section class=\"box-form\">
        {% for flash_message in app.flashes('danger') %}
            <div class=\"error\">
                <p>{{ flash_message }}</p>
            </div>
        {% endfor %}

        <div class=\"gradient\">
            <div class=\"row\">
                <h2>Restablecer contraseña</h2>
                <div>
                    {{ form_start(form, { 'action': path('resetting_reset', {'token': token}), 'attr': { 'class': 'fos_user_resetting_reset' } }) }}
                        {{ form_widget(form.plainPassword.first, {
                            'attr': {
                                'placeholder': 'Nueva contraseña',
                            }
                        }) }}
                        {{ form_errors(form.plainPassword.first) }}

                        {{ form_widget(form.plainPassword.second, {
                            'attr': {
                                'placeholder': 'Repita la contraseña',
                            }
                        }) }}
                        {{ form_errors(form.plainPassword.second) }}

                        <button type=\"submit\">Cambiar Contraseña</button>
                    {{ form_end(form) }}
                </div>
            </div>
        </div>
        <br />
    </section>
{% endblock %}
", "resetting/reset.html.twig", "C:\\pbstudio\\PBStudio81\\templates\\resetting\\reset.html.twig");
